# normalize / align / round helper modules
emit("fp16_normalize",
     "module fp16_normalize(input [13:0] mant_in, input signed [6:0] exp_in, output reg [9:0] mant_out, output reg [4:0] exp_out);\n"
     f"    // define mant_in input {COL['a']}   // define exp_in input {COL['b']}   // define mant_out output {COL['out']}\n"
     "    reg [13:0] m; reg signed [6:0] e; integer i;\n"
     "    always @(*) begin m=mant_in; e=exp_in;\n"
     "        if (m!=0) begin\n"
     "            for (i=0;i<13;i=i+1) if (!m[13]) begin m=m<<1; e=e-1; end\n"
     "        end\n"
     "        mant_out=m[12:3]; exp_out=(e<0)?5'b0:e[4:0];\n"
     "    end\nendmodule\n",
     ["fp16 mantissa normalizer (leading-1 alignment)."])
emit("fp16_round_nearest",
     "module fp16_round_nearest(input [12:0] mant_ext, output [9:0] mant);\n"
     f"    // define mant_ext input {COL['a']}   // define mant output {COL['out']}\n"
     "    // round-to-nearest-even on 3 guard bits\n"
     "    wire [9:0] base = mant_ext[12:3];\n"
     "    wire round_up = mant_ext[2] & (mant_ext[1] | mant_ext[0] | mant_ext[3]);\n"
     "    assign mant = base + round_up;\nendmodule\n",
     ["fp16 round-to-nearest-even unit."])

# int<->fp16 conversions
emit("int_to_fp16",
     "module int_to_fp16(input signed [15:0] n, output reg [15:0] y);\n"
     f"    // define n input {COL['a']}   // define y output {COL['out']}\n"
     "    reg sign; reg [15:0] mag; reg [4:0] e; reg [15:0] m; integer i;\n"
     "    always @(*) begin\n"
     "        if (n==0) y=16'b0;\n"
     "        else begin\n"
     "            sign=n[15]; mag = n[15] ? (~n+1) : n;\n"
     "            e=15+15; // start exp guess (bias + 15 max shift)\n"
     "            // find MSB position\n"
     "            m=mag;\n"
     "            for (i=0;i<16;i=i+1) if (!m[15]) begin m=m<<1; e=e-1; end\n"
     "            // m[15] is hidden 1; mantissa = next 10 bits\n"
     "            y={sign, e, m[14:5]};\n"
     "        end\n"
     "    end\nendmodule\n",
     ["signed int16 -> fp16 conversion."])
emit("fp16_to_int",
     "module fp16_to_int(input [15:0] a, output reg signed [15:0] n);\n"
     f"    // define a input {COL['a']}   // define n output {COL['out']}\n"
     "    reg sign; reg [4:0] e; reg [10:0] m; reg [15:0] val; integer sh;\n"
     "    always @(*) begin\n"
     "        sign=a[15]; e=a[14:10]; m={|e,a[9:0]};\n"
     "        if (e==0) n=0;\n"
     "        else begin\n"
     "            sh = e - 15 - 10;   // shift of mantissa to integer\n"
     "            if (sh>=0) val = m << sh; else val = m >> (-sh);\n"
     "            n = sign ? (~val+1) : val;\n"
     "        end\n"
     "    end\nendmodule\n",
     ["fp16 -> signed int16 (truncating)."])

# fp8 add/mul (compact educational)
emit("fp8_add",
     "module fp8_add(input [7:0] a, input [7:0] b, output reg [7:0] y);\n"
     f"    // define a input {COL['a']}   // define b input {COL['b']}   // define y output {COL['out']}\n"
     "    reg sa,sb; reg [3:0] ea,eb; reg [3:0] ma,mb;  // 4-bit incl hidden 1 (3 mantissa)\n"
     "    reg [6:0] mant_a,mant_b,sum_m; reg signed [5:0] exp_res; reg sign_res; integer i;\n"
     "    always @(*) begin\n"
     "        sa=a[7]; ea=a[6:3]; ma={|ea,a[2:0]};\n"
     "        sb=b[7]; eb=b[6:3]; mb={|eb,b[2:0]};\n"
     "        mant_a={ma,3'b0}; mant_b={mb,3'b0};\n"
     "        if (ea>eb) begin exp_res=ea; mant_b=mant_b>>(ea-eb); end\n"
     "        else begin exp_res=eb; mant_a=mant_a>>(eb-ea); end\n"
     "        if (sa==sb) begin sum_m=mant_a+mant_b; sign_res=sa; end\n"
     "        else if (mant_a>=mant_b) begin sum_m=mant_a-mant_b; sign_res=sa; end\n"
     "        else begin sum_m=mant_b-mant_a; sign_res=sb; end\n"
     "        if (sum_m==0) y=8'b0;\n"
     "        else begin\n"
     "            if (sum_m[6]) begin sum_m=sum_m>>1; exp_res=exp_res+1; end\n"
     "            else for (i=0;i<6;i=i+1) if (!sum_m[5]) begin sum_m=sum_m<<1; exp_res=exp_res-1; end\n"
     "            if (exp_res<=0) y={sign_res,7'b0};\n"
     "            else if (exp_res>=15) y={sign_res,4'b1111,3'b0};\n"
     "            else y={sign_res,exp_res[3:0],sum_m[4:2]};\n"
     "        end\n"
     "    end\nendmodule\n",
     ["fp8 (E4M3) adder, educational."])
emit("fp8_mul",
     "module fp8_mul(input [7:0] a, input [7:0] b, output reg [7:0] y);\n    // define a input 80.160.255   // define b input 80.200.255   // define y output 120.255.160\n    wire sa=a[7], sb=b[7];\n    wire [3:0] ea=a[6:3], eb=b[6:3];\n    wire [3:0] ma={|ea,a[2:0]}, mb={|eb,b[2:0]};\n    wire [7:0] prod_raw;\n    fp8m_mul mm(.a(ma), .b(mb), .product(prod_raw));\n    reg [7:0] prod; reg signed [5:0] exp_res;\n    always @(*) begin\n        if (ea==0||eb==0) y={sa^sb,7'b0};\n        else begin prod=prod_raw; exp_res=ea+eb-7;\n            if (prod[7]) begin prod=prod>>1; exp_res=exp_res+1; end\n            if (exp_res<=0) y={sa^sb,7'b0};\n            else if (exp_res>=15) y={sa^sb,4'b1111,3'b0};\n            else y={sa^sb,exp_res[3:0],prod[5:3]};\n        end\n    end\nendmodule\n\nmodule fp8m_mul(input [3:0] a, input [3:0] b, output [7:0] product);\n    wire pp0_0 = a[0] & b[0];\n    wire pp0_1 = a[1] & b[0];\n    wire pp0_2 = a[2] & b[0];\n    wire pp0_3 = a[3] & b[0];\n    wire pp1_0 = a[0] & b[1];\n    wire pp1_1 = a[1] & b[1];\n    wire pp1_2 = a[2] & b[1];\n    wire pp1_3 = a[3] & b[1];\n    wire pp2_0 = a[0] & b[2];\n    wire pp2_1 = a[1] & b[2];\n    wire pp2_2 = a[2] & b[2];\n    wire pp2_3 = a[3] & b[2];\n    wire pp3_0 = a[0] & b[3];\n    wire pp3_1 = a[1] & b[3];\n    wire pp3_2 = a[2] & b[3];\n    wire pp3_3 = a[3] & b[3];\n    wire [7:0] row0 = {1'b0, 1'b0, 1'b0, 1'b0, pp0_3, pp0_2, pp0_1, pp0_0};\n    wire [7:0] row1 = {1'b0, 1'b0, 1'b0, pp1_3, pp1_2, pp1_1, pp1_0, 1'b0};\n    wire [7:0] row2 = {1'b0, 1'b0, pp2_3, pp2_2, pp2_1, pp2_0, 1'b0, 1'b0};\n    wire [7:0] row3 = {1'b0, pp3_3, pp3_2, pp3_1, pp3_0, 1'b0, 1'b0, 1'b0};\n    wire [7:0] acc1; wire co1;\n    rca8 add1(.a(row0),.b(row1),.cin(1'b0),.sum(acc1),.cout(co1));\n    wire [7:0] acc2; wire co2;\n    rca8 add2(.a(acc1),.b(row2),.cin(1'b0),.sum(acc2),.cout(co2));\n    wire [7:0] acc3; wire co3;\n    rca8 add3(.a(acc2),.b(row3),.cin(1'b0),.sum(acc3),.cout(co3));\n    assign product = acc3;\nendmodule\n\nmodule rca8(input [7:0] a, input [7:0] b, input cin, output [7:0] sum, output cout);\n    wire [8:0] c; assign c[0]=cin;\n    full_adder fa0(.a(a[0]),.b(b[0]),.cin(c[0]),.sum(sum[0]),.cout(c[1]));\n    full_adder fa1(.a(a[1]),.b(b[1]),.cin(c[1]),.sum(sum[1]),.cout(c[2]));\n    full_adder fa2(.a(a[2]),.b(b[2]),.cin(c[2]),.sum(sum[2]),.cout(c[3]));\n    full_adder fa3(.a(a[3]),.b(b[3]),.cin(c[3]),.sum(sum[3]),.cout(c[4]));\n    full_adder fa4(.a(a[4]),.b(b[4]),.cin(c[4]),.sum(sum[4]),.cout(c[5]));\n    full_adder fa5(.a(a[5]),.b(b[5]),.cin(c[5]),.sum(sum[5]),.cout(c[6]));\n    full_adder fa6(.a(a[6]),.b(b[6]),.cin(c[6]),.sum(sum[6]),.cout(c[7]));\n    full_adder fa7(.a(a[7]),.b(b[7]),.cin(c[7]),.sum(sum[7]),.cout(c[8]));\n    assign cout=c[8];\nendmodule\n\nmodule half_adder(input a, input b, output sum, output carry);\n    assign sum   = a ^ b;\n    assign carry = a & b;\nendmodule\n\nmodule full_adder(input a, input b, input cin, output sum, output cout);\n    wire s0, c0, c1;\n    half_adder ha0(.a(a),  .b(b),   .sum(s0),  .carry(c0));\n    half_adder ha1(.a(s0), .b(cin), .sum(sum), .carry(c1));\n    assign cout = c0 | c1;\nendmodule\n",
     ['fp8 (E4M3) multiplier (structural 4x4 mantissa multiply); no * operator.'])

